worked_example.final_code:
public class EmiCalculator {
    public static String calculate(String principalStr, String rateStr, String tenureStr) {
        double principal, annualRate;
        int tenureMonths;

        try {
            principal    = Double.parseDouble(principalStr);
            annualRate   = Double.parseDouble(rateStr);
            tenureMonths = Integer.parseInt(tenureStr);
        } catch (NumberFormatException e) {
            return "Error: All inputs must be valid numbers.";
        }

        if (principal <= 0)    return "Error: Principal must be positive.";
        if (annualRate < 0)    return "Error: Rate cannot be negative.";
        if (tenureMonths <= 0) return "Error: Tenure must be at least 1 month.";

        if (annualRate == 0) {
            return String.format("EMI: ₹%.2f/month (0%% interest)", principal / tenureMonths);
        }

        double r   = annualRate / 12 / 100;
        double pow = Math.pow(1 + r, tenureMonths);
        double emi = principal * r * pow / (pow - 1);

        return String.format("EMI: ₹%.2f/month for %d months (total ₹%.2f)",
            emi, tenureMonths, emi * tenureMonths);
    }

    public static void main(String[] args) {
        System.out.println(calculate("500000", "8.5", "24"));
        System.out.println(calculate("5lakhs", "8.5", "24"));
        System.out.println(calculate("500000", "8.5", "0"));
        System.out.println(calculate("120000", "0", "12"));
    }
}

